                            addEdge(new BaseLabeledEdge("C -> G")).from(c).to(g);
                            addEdge(new BaseLabeledEdge("D -> G")).from(d).to(g);
                            addEdge(new BaseLabeledEdge("E -> F")).from(e).to(f);
